import React, { useCallback, useEffect, useMemo, useState } from 'react'
import { showToast } from '../../utils/toast'
import { useAuth } from '../../context/AuthContext'
import { taskService, pondService, productService, userService } from '../../services/api'
import '../../styles/technician/technician-tasks.css'

const STATUS_OPTIONS = [
  { value: 'ALL', label: 'Tất cả trạng thái công việc' },
  { value: 'PENDING', label: 'Chờ xử lý' },
  { value: 'IN_PROGRESS', label: 'Đang thực hiện' },
  { value: 'COMPLETED', label: 'Hoàn thành' },
]

const TASK_TYPE_OPTIONS = [
  { value: 'FEEDING', label: 'Cho ăn (FEEDING)' },
  { value: 'TREATMENT', label: 'Cho thuốc (TREATMENT)' },
  { value: 'HARVEST', label: 'Thu hoạch (HARVEST)' },
  { value: 'POND_PROCESS', label: 'Xử lý ao (POND_PROCESS)' },
]

const normalize = (v) => String(v || '').trim().toUpperCase()
const formatDate = (v) => (v ? new Date(v).toLocaleString('vi-VN') : '-')

const getStatusLabel = (status) => {
  switch (normalize(status)) {
    case 'PENDING': return 'Chờ xử lý'
    case 'IN_PROGRESS': return 'Đang thực hiện'
    case 'COMPLETED': return 'Hoàn thành'
    default: return status || '-'
  }
}

const getStatusClass = (status) => {
  switch (normalize(status)) {
    case 'PENDING': return 'table-status-badge table-status-inactive'
    case 'IN_PROGRESS': return 'table-status-badge table-status-active'
    case 'COMPLETED': return 'table-status-badge table-status-completed'
    default: return 'table-status-badge'
  }
}

const TechnicianTasks = () => {
  const { user } = useAuth()

  // ===== DATA STATE =====
  const [tasks, setTasks] = useState([])
  const [ponds, setPonds] = useState([])
  const [products, setProducts] = useState([])
  const [workers, setWorkers] = useState([])

  // ===== UI STATE =====
  const [loading, setLoading] = useState(true)
  const [search, setSearch] = useState('')
  const [statusFilter, setStatusFilter] = useState('ALL')
  const [currentPage, setCurrentPage] = useState(1)
  const [pageSize, setPageSize] = useState(10)
  const [selectedTask, setSelectedTask] = useState(null)
  const [isCreateOpen, setIsCreateOpen] = useState(false)

  // ===== FORM STATE =====
  const initialForm = {
    task_type: '',
    pond_id: '',
    description: '',
    due_date: '',
    assigned_workers: [], // Mảng chứa ID các Worker được phân công
    product_id: '',
    quantity: '',
  }
  const [form, setForm] = useState(initialForm)

  // =========================
  // FETCH DATA
  // =========================
  const fetchTasks = useCallback(async () => {
    try {
      const res = await taskService.getAllTasks()
      setTasks(res?.data?.data || [])
    } catch {
      showToast({ title: 'Không tải được danh sách công việc', type: 'error' })
    }
  }, [])

  const fetchPonds = useCallback(async () => {
    try {
      const res = await pondService.getAllPonds()
      setPonds(res?.data?.data || [])
    } catch {
      showToast({ title: 'Không tải được danh sách ao nuôi', type: 'error' })
    }
  }, [])

  const fetchProducts = useCallback(async () => {
    try {
      const res = await productService.getAllProducts()
      setProducts(res?.data?.data || [])
    } catch {
      showToast({ title: 'Không tải được danh mục sản phẩm', type: 'error' })
    }
  }, [])

  const fetchWorkers = useCallback(async () => {
    try {
      const res = await userService.getWorkers()
      setWorkers(res?.data?.data || [])
    } catch {
      showToast({ title: 'Không tải được danh sách nhân công', type: 'error' })
    }
  }, [])

  useEffect(() => {
    const loadAllData = async () => {
      setLoading(true)
      await Promise.all([
        fetchTasks(),
        fetchPonds(),
        fetchProducts(),
        fetchWorkers(),
      ])
      setLoading(false)
    }
    loadAllData()
  }, [fetchTasks, fetchPonds, fetchProducts, fetchWorkers])

  // =========================
  // FILTER LOGIC (MAIN TABLE)
  // =========================
  const filteredTasks = useMemo(() => {
    const s = search.trim().toLowerCase()
    return tasks.filter((t) => {
      const matchSearch = !s || 
        String(t.task_title || '').toLowerCase().includes(s) || 
        String(t.pond_name || '').toLowerCase().includes(s)
      
      const matchStatus = statusFilter === 'ALL' || normalize(t.status) === statusFilter
      return matchSearch && matchStatus
    })
  }, [tasks, search, statusFilter])

  const totalPages = Math.max(1, Math.ceil(filteredTasks.length / pageSize))
  useEffect(() => {
    if (currentPage > totalPages) {
      setCurrentPage(totalPages)
    }
  }, [filteredTasks.length, pageSize, totalPages, currentPage])

  const safePage = Math.min(currentPage, totalPages)
  const startIndex = (safePage - 1) * pageSize
  const endIndex = Math.min(startIndex + pageSize, filteredTasks.length)
  const paginatedTasks = filteredTasks.slice(startIndex, endIndex)

  // ===================================
  // FORM DEPENDENT FILTERS & NGHIEP VU
  // ===================================
  
  // 1. Lọc danh sách ao thuộc quyền quản lý của Kỹ sư hiện tại & Theo trạng thái phù hợp loại công việc
  const myFilteredPonds = useMemo(() => {
    // Chỉ lấy ao mà kỹ sư này phụ trách
    const myPonds = ponds.filter(p => Number(p.assigned_staff) === Number(user?.user_id))

    if (!form.task_type) return myPonds

    switch (form.task_type) {
      case 'FEEDING':
      case 'TREATMENT':
      case 'HARVEST':
        // Các công việc này yêu cầu ao phải "Đang nuôi"
        return myPonds.filter((p) => normalize(p.status) === 'DANG_NUOI')
      case 'POND_PROCESS':
        // Xử lý ao yêu cầu ao phải "Đang cải tạo"
        return myPonds.filter((p) => normalize(p.status) === 'DANG_CAI_TAO')
      default:
        return myPonds
    }
  }, [ponds, form.task_type, user])

  // 2. Kiểm tra loại công việc hiện tại có cần vật tư/sản phẩm đi kèm không
  const isProductRequired = useMemo(() => {
    return ['FEEDING', 'TREATMENT', 'POND_PROCESS'].includes(form.task_type)
  }, [form.task_type])

  // 3. Lọc sản phẩm tương ứng với từng loại công việc cụ thể
  const filteredProducts = useMemo(() => {
    if (!form.task_type) return []
    switch (form.task_type) {
      case 'FEEDING':
        return products.filter((p) => normalize(p.type) === 'FEED') // Thức ăn
      case 'TREATMENT':
        return products.filter((p) => normalize(p.type) === 'MEDICINE') // Thuốc thủy sản
      case 'POND_PROCESS':
        return products.filter((p) => normalize(p.type) === 'CHEMICAL') // Hóa chất xử lý ao
      default:
        return []
    }
  }, [products, form.task_type])

  // 4. Lọc danh sách Worker (Công nhân) thuộc quyền quản lý của kỹ sư hiện tại
  const myManagedWorkers = useMemo(() => {
    return workers.filter(w => Number(w.managed_by) === Number(user?.user_id))
  }, [workers, user])

  // =========================
  // ACTION HANDLERS
  // =========================
  const toggleWorker = (id) => {
    setForm((prev) => {
      const list = prev.assigned_workers || []
      const exists = list.includes(id)
      return {
        ...prev,
        assigned_workers: exists ? list.filter((x) => x !== id) : [...list, id],
      }
    })
  }

  const handleCreateTask = async () => {
    try {
      // Chuẩn bị dữ liệu gửi lên API (loại bỏ trường sản phẩm nếu loại công việc không cần dùng)
      const submitData = { ...form }
      if (!isProductRequired) {
        delete submitData.product_id
        delete submitData.quantity
      }

      await taskService.createTask(submitData)
      showToast({ title: 'Phân công công việc mới thành công', type: 'success' })
      setForm(initialForm)
      setIsCreateOpen(false)
      await fetchTasks()
    } catch {
      showToast({ title: 'Tạo công việc thất bại', type: 'error' })
    }
  }

  const handleStatusChange = async (taskId, newStatus) => {
    try {
      await taskService.updateTaskStatus(taskId, newStatus)
      showToast({ title: 'Cập nhật trạng thái công việc thành công', type: 'success' })
      setSelectedTask(null)
      await fetchTasks()
    } catch {
      showToast({ title: 'Lỗi cập nhật trạng thái công việc', type: 'error' })
    }
  }

  if (loading) {
    return (
      <div className="dashboard admin-page">
        <div className="flex-center table-loading-container">
          <div className="spinner" />
        </div>
      </div>
    )
  }

  return (
    <div className="dashboard admin-page technician-tasks">
      <div className="table-container table-panel">
        
        {/* HEADER */}
        <div className="table-header">
          <div>
            <h2>Quản lý công việc</h2>
            <p className="table-subtitle">Phân công và giám sát tiến độ công việc kỹ thuật</p>
          </div>
          <button type="button" className="btn btn-primary" onClick={() => setIsCreateOpen(true)}>
            + Phân công công việc
          </button>
        </div>

        {/* TOOLBAR & FILTER */}
        <div className="table-toolbar">
          <div className="table-search">
            <span className="table-search-icon">⌕</span>
            <input
              type="text"
              placeholder="Tìm theo tên công việc hoặc ao..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
          </div>

          <select
            className="table-filter"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
          >
            {STATUS_OPTIONS.map((o) => (
              <option key={o.value} value={o.value}>{o.label}</option>
            ))}
          </select>
        </div>

        {/* DATA TABLE */}
        <div className="table-wrapper">
          <table className="table-base">
            <thead>
              <tr>
                <th>Công việc</th>
                <th>Ao nuôi</th>
                <th>Người giao</th>
                <th>Người thực hiện</th>
                <th>Hạn hoàn thành</th>
                <th>Trạng thái</th>
                <th>Hành động</th>
              </tr>
            </thead>
            <tbody>
              {paginatedTasks.length === 0 ? (
                <tr>
                  <td className="table-empty-row" colSpan="7">
                    Không có dữ liệu công việc phù hợp bộ lọc hiện tại.
                  </td>
                </tr>
              ) : (
                paginatedTasks.map((t) => (
                  <tr key={t.task_id}>
                    <td>
                      <div className="technician-ponds_name-block">
                        <strong>{t.task_title}</strong>
                        <span style={{ fontSize: '0.85rem', color: '#64748b' }}>{t.description}</span>
                      </div>
                    </td>
                    <td>{t.pond_name || '-'}</td>
                    <td>{t.assigned_by_name || '-'}</td>
                    <td>{t.assigned_to_name || '-'}</td>
                    <td>{formatDate(t.due_date)}</td>
                    <td>
                      <span className={getStatusClass(t.status)}>
                        {getStatusLabel(t.status)}
                      </span>
                    </td>
                    <td>
                      <div className="table-actions">
                        <button
                          type="button"
                          className="table-action-btn table-action-btn--view"
                          title="Xem chi tiết & Cập nhật"
                          onClick={() => setSelectedTask(t)}
                        >
                          ⓘ
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        {/* PAGINATION */}
        <div className="table-pagination">
          <div className="table-pagination-left">
            <span>Số mục trên trang</span>
            <select
              value={pageSize}
              onChange={(e) => {
                setPageSize(Number(e.target.value) || 10)
                setCurrentPage(1)
              }}
            >
              {[5, 10, 20, 50].map((size) => (
                <option key={size} value={size}>{size}</option>
              ))}
            </select>
            <span>{filteredTasks.length === 0 ? 0 : startIndex + 1}-{endIndex} / {filteredTasks.length}</span>
          </div>

          <div className="table-pagination-right">
            <button
              type="button"
              className="btn btn-sm btn-secondary"
              disabled={safePage <= 1}
              onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
            >
              ‹
            </button>
            <span className="table-page-pill">{safePage}</span>
            <button
              type="button"
              className="btn btn-sm btn-secondary"
              disabled={safePage >= totalPages}
              onClick={() => setCurrentPage((p) => Math.min(totalPages, p + 1))}
            >
              ›
            </button>
          </div>
        </div>
      </div>

      {/* DETAIL MODAL */}
      {selectedTask && (
        <div className="modal" onClick={() => setSelectedTask(null)}>
          <div className="modal-content admin-users_modal admin-users_modal--detail" onClick={(e) => e.stopPropagation()}>
            <h3>Chi tiết công việc</h3>
            
            <div className="admin-users_detail-grid">
              <div className="admin-users_detail-card">
                <span className="admin-users_detail-label">Tiêu đề công việc</span>
                <strong>{selectedTask.task_title || '-'}</strong>
              </div>
              <div className="admin-users_detail-card">
                <span className="admin-users_detail-label">Ao nuôi áp dụng</span>
                <strong>{selectedTask.pond_name || '-'}</strong>
              </div>
              <div className="admin-users_detail-card">
                <span className="admin-users_detail-label">Thời hạn</span>
                <strong>{formatDate(selectedTask.due_date)}</strong>
              </div>
              <div className="admin-users_detail-card">
                <span className="admin-users_detail-label">Trạng thái hiện tại</span>
                <span className={getStatusClass(selectedTask.status)} style={{ display: 'inline-block', marginTop: '4px' }}>
                  {getStatusLabel(selectedTask.status)}
                </span>
              </div>
              <div className="admin-users_detail-card" style={{ gridColumn: 'span 2' }}>
                <span className="admin-users_detail-label">Mô tả công việc</span>
                <p style={{ margin: '4px 0 0', color: '#334155' }}>{selectedTask.description || 'Không có mô tả.'}</p>
              </div>
            </div>

            <div style={{ marginTop: '20px' }}>
              <label className="admin-users_detail-label" style={{ marginBottom: '6px', display: 'block' }}>
                Cập nhật trạng thái tiến độ:
              </label>
              <select
                className="table-filter"
                style={{ width: '100%', padding: '8px 12px' }}
                value={selectedTask.status}
                onChange={(e) => handleStatusChange(selectedTask.task_id, e.target.value)}
              >
                <option value="PENDING">Chờ xử lý</option>
                <option value="IN_PROGRESS">Đang thực hiện</option>
                <option value="COMPLETED">Hoàn thành</option>
              </select>
            </div>

            <div className="admin-users_modal-buttons admin-users_form-buttons" style={{ marginTop: '24px' }}>
              <button type="button" className="btn btn-secondary" onClick={() => setSelectedTask(null)}>Đóng</button>
            </div>
          </div>
        </div>
      )}

      {/* CREATE TASK MODAL (ĐÃ ĐIỀU CHỈNH THEO YÊU CẦU MỚI) */}
      {isCreateOpen && (
        <div className="modal" onClick={() => setIsCreateOpen(false)}>
          <div className="modal-content admin-users_modal" style={{ maxWidth: '650px' }} onClick={(e) => e.stopPropagation()}>
            <h3>Phân công công việc mới</h3>
            
            <div style={{ display: 'flex', flexDirection: 'column', gap: '16px', marginTop: '16px' }}>
              
              {/* 1. LOẠI CÔNG VIỆC */}
              <div>
                <label className="admin-users_detail-label">Loại công việc <span style={{ color: 'red' }}>*</span></label>
                <select
                  className="table-filter"
                  style={{ width: '100%', marginTop: '4px' }}
                  value={form.task_type}
                  onChange={(e) => setForm({ ...form, task_type: e.target.value, pond_id: '', product_id: '', quantity: '' })}
                >
                  <option value="">-- Chọn loại công việc --</option>
                  {TASK_TYPE_OPTIONS.map(opt => (
                    <option key={opt.value} value={opt.value}>{opt.label}</option>
                  ))}
                </select>
              </div>

              {/* 2. AO NUÔI (LỌC THEO QUYỀN QUẢN LÝ VÀ LOẠI CÔNG VIỆC) */}
              <div>
                <label className="admin-users_detail-label">Ao nuôi áp dụng <span style={{ color: 'red' }}>*</span></label>
                <select
                  className="table-filter"
                  style={{ width: '100%', marginTop: '4px' }}
                  value={form.pond_id}
                  disabled={!form.task_type}
                  onChange={(e) => setForm({ ...form, pond_id: e.target.value })}
                >
                  <option value="">-- Chọn ao nuôi ({myFilteredPonds.length} ao sẵn sàng) --</option>
                  {myFilteredPonds.map((p) => (
                    <option key={p.pond_id} value={p.pond_id}>
                      {p.pond_name} ({getPondStatusLabel(p.status)})
                    </option>
                  ))}
                </select>
              </div>

              {/* 3. MÔ TẢ CÔNG VIỆC (TÙY CHỌN) */}
              <div>
                <label className="admin-users_detail-label">Mô tả công việc (Không bắt buộc)</label>
                <textarea
                  placeholder="Nhập mô tả hoặc ghi chú các hạng mục cụ thể..."
                  style={{ width: '100%', marginTop: '4px', minHeight: '60px', padding: '8px', borderRadius: '4px', border: '1px solid #cbd5e1' }}
                  value={form.description}
                  onChange={(e) => setForm({ ...form, description: e.target.value })}
                />
              </div>

              {/* 4. SẢN PHẨM & SỐ LƯỢNG ĐI KÈM (ẨN/HIỆN ĐỘNG THEO LOẠI CÔNG VIỆC) */}
              {isProductRequired && (
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', background: '#f8fafc', padding: '12px', borderRadius: '6px', border: '1px dashed #cbd5e1' }}>
                  <div>
                    <label className="admin-users_detail-label">Sản phẩm cần dùng</label>
                    <select
                      className="table-filter"
                      style={{ width: '100%', marginTop: '4px' }}
                      value={form.product_id}
                      onChange={(e) => setForm({ ...form, product_id: e.target.value })}
                    >
                      <option value="">-- Chọn sản phẩm --</option>
                      {filteredProducts.map((p) => (
                        <option key={p.product_id} value={p.product_id}>{p.product_name}</option>
                      ))}
                    </select>
                  </div>
                  <div>
                    <label className="admin-users_detail-label">Số lượng</label>
                    <input
                      type="number"
                      placeholder="Nhập số lượng..."
                      style={{ width: '100%', marginTop: '4px', padding: '6px 12px', borderRadius: '4px', border: '1px solid #cbd5e1' }}
                      value={form.quantity}
                      min="0"
                      onChange={(e) => setForm({ ...form, quantity: Number(e.target.value) || 0 })}
                    />
                  </div>
                </div>
              )}

              {/* 5. THỜI GIAN HOÀN THÀNH */}
              <div>
                <label className="admin-users_detail-label">Hạn chót hoàn thành <span style={{ color: 'red' }}>*</span></label>
                <input
                  type="datetime-local"
                  style={{ width: '100%', marginTop: '4px', padding: '8px', borderRadius: '4px', border: '1px solid #cbd5e1' }}
                  value={form.due_date}
                  onChange={(e) => setForm({ ...form, due_date: e.target.value })}
                />
              </div>

              {/* 6. DANH SÁCH WORKER PHỤ TRÁCH (DẠNG MA TRẬN CHOOSE GRID) */}
              <div>
                <label className="admin-users_detail-label" style={{ marginBottom: '6px', display: 'block' }}>
                  Phân công nhân công phụ trách ({myManagedWorkers.length} người thuộc tổ của bạn)
                </label>
                {myManagedWorkers.length === 0 ? (
                  <p style={{ fontStyle: 'italic', color: '#94a3b8', fontSize: '0.9rem' }}>Bạn chưa được phân quyền quản lý công nhân nào.</p>
                ) : (
                  <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px', maxHeight: '150px', overflowY: 'auto', padding: '8px', border: '1px solid #e2e8f0', borderRadius: '6px' }}>
                    {myManagedWorkers.map((w) => {
                      const isChecked = form.assigned_workers?.includes(w.user_id)
                      return (
                        <label 
                          key={w.user_id} 
                          style={{ display: 'flex', alignItems: 'center', gap: '8px', padding: '6px', borderRadius: '4px', background: isChecked ? '#f0fdf4' : 'transparent', border: isChecked ? '1px solid #bbf7d0' : '1px solid transparent', cursor: 'pointer' }}
                        >
                          <input
                            type="checkbox"
                            checked={isChecked}
                            onChange={() => toggleWorker(w.user_id)}
                          />
                          <div style={{ display: 'flex', flexDirection: 'column' }}>
                            <strong style={{ fontSize: '0.9rem' }}>{w.full_name}</strong>
                            <span style={{ fontSize: '0.75rem', color: '#64748b' }}>{w.username}</span>
                          </div>
                        </label>
                      )
                    })}
                  </div>
                )}
              </div>

            </div>

            {/* BUTTON ACTIONS */}
            <div className="admin-users_modal-buttons admin-users_form-buttons" style={{ marginTop: '24px' }}>
              <button type="button" className="btn btn-secondary" onClick={() => setIsCreateOpen(false)}>Hủy</button>
              <button 
                type="button" 
                className="btn btn-primary" 
                onClick={handleCreateTask} 
                disabled={!form.task_type || !form.pond_id || !form.due_date}
              >
                Xác nhận phân công
              </button>
            </div>
          </div>
        </div>
      )}

    </div>
  )
}

const getPondStatusLabel = (status) => {
  switch (normalize(status)) {
    case 'CHUAN_BI_NUOI': return 'Chuẩn bị nuôi'
    case 'DANG_NUOI': return 'Đang nuôi'
    case 'DANG_CAI_TAO': return 'Đang cải tạo'
    case 'TAM_NGUNG': return 'Tạm ngưng'
    default: return status || '-'
  }
}

export default TechnicianTasks
